  KEY `idx_tender_is_locked` (`is_locked`),
  KEY `idx_tender_prebid_status` (`pre_bid_meeting_status`),
  KEY `idx_tender_version` (`tender_version`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
